INSERT INTO `notifications` (`id`, `title`, `message`, `image_url`, `image_path`, `notification_type`, `target_type`, `shop_ids`, `user_ids`, `created_by`, `created_at`, `updated_at`, `is_active`, `scheduled_for`, `expires_at`, `views_count`, `priority`) VALUES
(1, 'Test1', 'Why MySQL is ideal for SaaS\r\nStructured data → orders, invoices, GST, users, reports\r\nStrong relationships → customers ↔ orders ↔ items\r\nACID transactions → critical for billing & payments\r\nEasy reporting → revenue, tax, analytics (VERY important for POS/PMS)\r\nMulti-tenant support → handle multiple restaurants/hotels\r\n✅ Perfect for your use case (ChefMate POS)\r\nOrders & billing\r\nGST/tax calculation\r\nInventory\r\nReports (daily/monthly revenue)\r\nUser roles & permissions\r\n\r\n👉 Basically: All business logic = MySQL', 'http://localhost:4402/uploads/notifications/notification-1774592055964-939467376.png', '/uploads/notifications/notification-1774592055964-939467376.png', 'general', 'all', NULL, NULL, 1, '2026-03-27 06:14:15', '2026-03-27 06:14:15', 1, '2026-03-26 17:00:00', '2026-03-27 17:00:00', 0, 'normal'),
(2, 'fdsfs', 'fdsfdsfdsfdsfdsf', NULL, NULL, 'announcement', 'all', NULL, NULL, 1, '2026-03-27 06:24:24', '2026-03-27 06:24:24', 1, NULL, NULL, 0, 'high'),
(3, 'test2', '🧠 Best Architecture (Recommended for YOU)\r\n\r\n👉 Hybrid approach (industry standard):\r\n\r\nMySQL → Core database (orders, billing, reports)\r\nFirebase → Realtime + notifications\r\nExample:\r\nOrder placed → stored in MySQL\r\nKitchen screen → updates via Firebase realtime\r\nNotification → Firebase Cloud Messaging', NULL, NULL, 'promotion', 'specific_shops', '\"[3,2]\"', NULL, 1, '2026-03-27 06:48:46', '2026-03-27 06:48:46', 1, NULL, NULL, 0, 'high'),
(4, 'Regulare Maintainance ', 'We are going to under maintainenance on 25 march 2026 for 2-3 hours start from 10:00 am', NULL, NULL, 'alert', 'all', NULL, NULL, 1, '2026-03-27 07:04:23', '2026-03-27 07:04:23', 1, NULL, NULL, 0, 'high'),
(5, 'alert hacker attack', 'HAckers try to access our server .. try to save your data abckup', 'http://localhost:4402/uploads/notifications/notification-1774595402589-900919578.png', '/uploads/notifications/notification-1774595402589-900919578.png', 'alert', 'specific_shops', '\"[3]\"', NULL, 1, '2026-03-27 07:10:02', '2026-03-27 07:10:02', 1, NULL, NULL, 0, 'urgent'),
(6, 'sfdfsdfdsfsfs', 'fdsfs fsdfdsf fffsdfsdfsdfdsfds', NULL, NULL, 'general', 'all', NULL, NULL, 1, '2026-03-27 07:10:34', '2026-03-27 07:10:34', 1, NULL, NULL, 0, 'normal'),
(7, 'dgdfgdfgfdg', 'gfdgfdgfdgfdgfdgg \r\nGdfgfdgdfggfdgfddfgg', 'http://localhost:4402/uploads/notifications/notification-1774595910175-322404921.jpg', '/uploads/notifications/notification-1774595910175-322404921.jpg', 'general', 'specific_shops', '\"[3]\"', NULL, 1, '2026-03-27 07:18:30', '2026-03-27 07:18:30', 1, NULL, NULL, 0, 'normal'),
